# Test file for ast_pure_functions macro
# Contains a mix of pure and impure functions

# ── Pure functions ────────────────────────────────────────────────────────────

def add(x, y):
    """Pure: arithmetic on parameters only."""
    return x + y


def multiply(a, b):
    """Pure: arithmetic on parameters only."""
    return a * b


def clamp(value, lo, hi):
    """Pure: comparison and conditional on parameters only."""
    if value < lo:
        return lo
    if value > hi:
        return hi
    return value


def format_name(first, last):
    """Pure: string concatenation on parameters."""
    return first + " " + last


def max_of_three(a, b, c):
    """Pure: logic on parameters; nested helper defined locally."""
    def _max2(x, y):
        return x if x > y else y
    return _max2(_max2(a, b), c)


# ── Impure: external function calls ──────────────────────────────────────────

def greet(name):
    """Impure: calls external print()."""
    print("Hello, " + name)


def read_file(path):
    """Impure: calls external open()."""
    with open(path) as f:
        return f.read()


def get_length(items):
    """Impure: calls external len()."""
    return len(items)


def parse_int(s):
    """Impure: calls external int()."""
    return int(s)


# ── Impure: global / nonlocal keyword ────────────────────────────────────────

_counter = 0

def increment_counter():
    """Impure: explicitly modifies global state."""
    global _counter
    _counter += 1


# ── Impure: attribute access on non-parameter objects ────────────────────────

import os

def get_cwd():
    """Impure: accesses os (not a parameter) attribute."""
    return os.getcwd()


class Config:
    debug = False

def is_debug():
    """Impure: accesses Config (not a parameter) attribute."""
    return Config.debug


# ── Mixed: method calls on parameters (receiver is a param → still a call) ──

def upper_name(name):
    """Impure: calls str.upper — name.upper() is an external method call."""
    return name.upper()
